const HOST = '127.0.0.1';

// In-memory store
let tickets = [];

// Load data from file at startup
function loadData() {
    try {
        const data = fs.readFileSync(DATA_FILE, 'utf8');
        tickets = JSON.parse(data);
        if (!Array.isArray(tickets)) tickets = [];
    } catch (err) {
        if (err.code === 'ENOENT') {
            tickets = [];
        } else {
            console.error('Failed to load data:', err);
            tickets = [];
        }
    }
}

